task myGreeting {
    group = 'custom'
    description = 'Prints a message and writes it to a file'
    def msg = 'Hello World'
    inputs.property('message', msg)
    outputs.file(file('build/greeting.txt'))

    doLast {
        println msg
        file('build/greeting.txt').text = msg
    } 
}

